import{promises as i}from"node:fs";import{dirname as n}from"node:path";export async function ensureDir(t){await i.mkdir(t,{recursive:!0})}export async function readJson(t){try{const r=await i.readFile(t,"utf8");return JSON.parse(r)}catch{return null}}export async function writeJson(t,r){await ensureDir(n(t)),await i.writeFile(t,JSON.stringify(r,null,2),"utf8")}export async function writeText(t,r){await ensureDir(n(t)),await i.writeFile(t,r,"utf8")}
